import urllib.parse
import urllib.request
import json

def llm_chat(prompt):
    url = "http://localhost:8000/api/chat"
    data = json.dumps({"model": "ail-coder:7b-v3", "messages": [{"role": "user", "content": prompt}], "stream": False}).encode()
    req = urllib.request.Request(url, data, headers={"Content-Type": "application/json"})
    with urllib.request.urlopen(req) as f:
        response = json.loads(f.read().decode())
    return response['message']['content']

def char_freq(text):
    freq = {}
    for char in text:
        if char in freq:
            freq[char] += 1
        else:
            freq[char] = 1
    return freq

def describe_pattern(freq):
    sorted_freq = sorted(freq.items(), key=lambda x: x[1], reverse=True)
    pattern = []
    for char, count in sorted_freq:
        pattern.append(f"{char}: {count}")
    return "Pattern: " + ", ".join(pattern)

text = 'hello world'
freq = char_freq(text)
pattern = describe_pattern(freq)
print(pattern)

