pure fn percentile_of(value: Number, sorted_nums: [Number]) -> Number {
    n = length(sorted_nums)
    rank = 0
    for i in range(0, n) {
        if sorted_nums[i] <= value { rank = rank + 1 }
    }
    return rank / n
}
