pure fn mean(nums: Any) -> Number {
    total = 0
    for n in nums { total = total + n }
    return total / length(nums)
}
pure fn variance(nums: Any) -> Number {
    avg = mean(nums)
    total = 0
    for n in nums { total = total + (n - avg) * (n - avg) }
    return total / length(nums)
}
pure fn std_dev(nums: Any) -> Number {
    return sqrt(variance(nums))
}
entry main(x: Text) {
    nums = [10, 12, 23, 23, 16, 23, 21, 16]
    std_dev_value = std_dev(nums)
