import re
from urllib.parse import urlencode
from urllib.request import Request, urlopen

def ollama_chat(prompt):
    url = 'http://localhost:8000/api/chat'
    data = {'model': 'ail-coder:7b-v3', 'prompt': prompt, 'stream': 'false'}
    req = Request(url, data=urlencode(data).encode(), headers={'Content-Type': 'application/x-www-form-urlencoded'})
    with urlopen(req) as f:
        response = f.read()
    return response.decode()

def validate_email(email):
    return re.match(r"[^@]+@[^@]+\.[^@]+", email) is not None

def draft_greeting(email):
    return f"Hello {email.split('@')[0]}, how can I assist you today?"

def main():
    text = 'Contact alice@test.com or bob@test.com for info'
    emails = re.findall(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b', text)
    greetings = []
    for email in emails:
        if validate_email(email):
            greetings.append(draft_greeting(email))
    return '\n'.join(greetings)

print(main())

